// FTC-WF-003: Calcular dias hasta vencimiento y clasificar registros
// Categorias: 30 dias, 15 dias, 7 dias desde hoy

const items = $input.all();
const today = new Date();
today.setHours(0, 0, 0, 0);

const results = {
  group_30: [],
  group_15: [],
  group_7: [],
  skipped: []
};

for (const item of items) {
  const props = item.json.properties || item.json;

  // Obtener fecha de vencimiento del campo Fecha_Vencimiento
  const fechaVencimientoRaw =
    props.Fecha_Vencimiento?.date?.start ||
    props.Fecha_Vencimiento?.start ||
    props.fecha_vencimiento?.date?.start ||
    props.fecha_vencimiento?.start ||
    null;

  if (!fechaVencimientoRaw) {
    results.skipped.push({
      id: item.json.id,
      reason: 'Sin fecha de vencimiento'
    });
    continue;
  }

  const fechaVencimiento = new Date(fechaVencimientoRaw);
  fechaVencimiento.setHours(0, 0, 0, 0);

  const diffTime = fechaVencimiento.getTime() - today.getTime();
  const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));

  // Obtener datos relevantes del registro
  const record = {
    id: item.json.id,
    pageUrl: item.json.url || '',
    diasRestantes: diffDays,
    fechaVencimiento: fechaVencimientoRaw,
    estadoPago:
      props.Estado_Pago?.select?.name ||
      props.Estado_Pago?.name ||
      props.estado_pago?.select?.name ||
      'Desconocido',
    empresaRelation:
      props.Empresa?.relation?.[0]?.id ||
      props.empresa?.relation?.[0]?.id ||
      null,
    nombreEmpresa:
      props.Nombre_Empresa?.title?.[0]?.plain_text ||
      props.nombre_empresa?.title?.[0]?.plain_text ||
      props.Empresa_Nombre?.rich_text?.[0]?.plain_text ||
      'Empresa no identificada',
    tipoMembresia:
      props.Tipo_Membresia?.select?.name ||
      props.tipo_membresia?.select?.name ||
      'No especificada',
    montoRenovacion:
      props.Monto_Renovacion?.number ||
      props.monto_renovacion?.number ||
      null,
    ejecutivoAsignado:
      props.Ejecutivo_Asignado?.people?.[0]?.name ||
      props.ejecutivo_asignado?.people?.[0]?.name ||
      null,
    ejecutivoEmail:
      props.Ejecutivo_Asignado?.people?.[0]?.person?.email ||
      props.ejecutivo_asignado?.people?.[0]?.person?.email ||
      null,
    ultimaAlerta:
      props.Ultima_alerta_enviada?.date?.start ||
      props.ultima_alerta_enviada?.date?.start ||
      null
  };

  // Clasificar por dias exactos para evitar spam
  // Se envia alerta en el dia exacto (30, 15, 7) o si nunca se ha enviado
  // y esta dentro del rango
  if (diffDays === 30) {
    results.group_30.push(record);
  } else if (diffDays === 15) {
    results.group_15.push(record);
  } else if (diffDays === 7) {
    results.group_7.push(record);
  } else if (diffDays > 0 && diffDays < 7 && !record.ultimaAlerta) {
    // Si faltan menos de 7 dias y nunca se envio alerta, incluir en grupo 7
    results.group_7.push(record);
  } else {
    results.skipped.push({
      id: item.json.id,
      diasRestantes: diffDays,
      reason: 'Fuera de ventana de alerta'
    });
  }
}

return [
  {
    json: {
      group_30: results.group_30,
      group_15: results.group_15,
      group_7: results.group_7,
      skipped: results.skipped,
      summary: {
        total_procesados: items.length,
        alertas_30d: results.group_30.length,
        alertas_15d: results.group_15.length,
        alertas_7d: results.group_7.length,
        omitidos: results.skipped.length,
        fecha_ejecucion: today.toISOString()
      }
    }
  }
];

// Expandir grupo 30 dias en items individuales
const group = $('Clasificar por Dias Restantes').first().json.group_30;
return group.map(record => ({ json: record }));

// Expandir grupo 15 dias en items individuales
const group = $('Clasificar por Dias Restantes').first().json.group_15;
return group.map(record => ({ json: record }));

// Expandir grupo 7 dias en items individuales
const group = $('Clasificar por Dias Restantes').first().json.group_7;
return group.map(record => ({ json: record }));

