const props = empresa.properties || empresa;

const contactoEmail =
  props.Email_Contacto?.email ||
  props.email_contacto?.email ||
  props.Email?.email ||
  props.email?.email ||
  null;

const contactoNombre =
  props.Contacto_Principal?.rich_text?.[0]?.plain_text ||
  props.contacto_principal?.rich_text?.[0]?.plain_text ||
  props.Nombre_Contacto?.rich_text?.[0]?.plain_text ||
  'Estimado/a asociado/a';

const nombreEmpresa =
  props.Nombre?.title?.[0]?.plain_text ||
  props.nombre?.title?.[0]?.plain_text ||
  props.Name?.title?.[0]?.plain_text ||
  renovacion.nombreEmpresa;

return [{
  json: {
    ...renovacion,
    contactoEmail,
    contactoNombre,
    nombreEmpresa,
    empresaPageUrl: empresa.url || ''
  }
}];

